import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const porLessonsB1: Lesson[] = [
  createLesson('g3-por-b1-l1', 'L1: 3ª Série — O Ano do ENEM', 'portugues', 'A 3ª série é o ano decisivo. O ENEM: estrutura (45 questões de Linguagens + Redação), peso da redação (20% da nota de Linguagens), cronograma (novembro). Língua Portuguesa no ENEM: interpretação de textos variados, literatura, gramática em contexto, figuras de linguagem, variação linguística, gêneros textuais. A Redação: 5 competências, 0-1000 pontos. Planejamento estratégico: o que revisar e quando. Mentalidade: consistência supera intensidade de última hora.', ['Monte um calendário de estudos de LP para a 3ª série até o ENEM.', 'Qual é a sua maior dificuldade em Língua Portuguesa para o ENEM? Como vai trabalhar nela?']),
  createLesson('g3-por-b1-l2', 'L2: Diagnóstico Completo — Todos os Conteúdos', 'portugues', 'Teste diagnóstico abrangente: todas as habilidades de LP do ENEM. Interpretação de textos (narrativo, poético, dissertativo, publicitário, multimodal), literatura (identificar escolas e características), gramática em contexto (concordância, regência, crase, pontuação, colocação pronominal), figuras de linguagem, variação linguística, gêneros textuais, redação (planejamento). Resultado: mapa personalizado das lacunas de cada aluno. Não é avaliação — é diagnóstico.', ['Complete o diagnóstico de 25 questões abrangendo todos os conteúdos de LP.', 'Com base nos resultados, quais são suas 5 prioridades de estudo para o 1º Bimestre?']),
  createLesson('g3-por-b1-l3', 'L3: Interpretação Textual — Masterclass', 'portugues', 'Masterclass em interpretação: as 8 habilidades mais cobradas no ENEM. H1: identificar tema/tese. H2: localizar informações explícitas. H3: inferir informações implícitas. H4: identificar o efeito de recursos expressivos. H5: reconhecer o propósito/função do texto. H6: identificar a organização/estrutura textual. H7: reconhecer relações de intertextualidade. H8: avaliar criticamente o texto. Cada habilidade com exemplos e questões práticas do ENEM.', ['Para cada habilidade, resolva 2 questões do ENEM que a testam.', 'Qual habilidade de interpretação é mais difícil para você? Crie um plano específico.']),
  createLesson('g3-por-b1-l4', 'L4: Literatura no ENEM — Mapeamento Completo', 'portugues', 'Mapeamento de como o ENEM cobra literatura. Fragmentos literários: sempre acompanhados de questão de interpretação — não de memorização. Características textuais que revelam a escola literária. Frequência de cada escola no ENEM (2009-2024): Modernismo (30%+), Romantismo (15%), Realismo (15%), Barroco (10%), outros (30%). Autores mais citados: Drummond, Machado, Guimarães Rosa, Clarice, Pessoa, Eça. Estratégia: saber interpretar fragmentos de qualquer escola.', ['Resolva estas 10 questões de literatura do ENEM sem ver os títulos dos textos: identifique a escola pelo texto.', 'Crie um mapa mental das características distintivas de cada escola literária.']),
  createLesson('g3-por-b1-l5', 'L5: Redação ENEM — Competência 1 (Norma Culta)', 'portugues', 'Competência 1: demonstrar domínio da modalidade escrita formal da língua portuguesa. Peso: 200 pontos. O que é avaliado: ortografia, acentuação, pontuação, concordância, regência, colocação pronominal, crase, paragrafação, uso de letras maiúsculas/minúsculas. Erros graves (descontam muito): trocar l/r, concordância flagrante, falta de paragrafação. Erros leves (descontam menos): vírgula a mais, acento incorreto. Como a norma culta é avaliada na prática. Treino específico.', ['Corrija todos os erros de Competência 1 nesta redação (nota real: 600).', 'Escreva um parágrafo sem nenhum erro de norma culta sobre o tema sugerido.']),
  createLesson('g3-por-b1-l6', 'L6: Redação ENEM — Competência 2 (Compreensão do Tema)', 'portugues', 'Competência 2: compreender a proposta de redação e aplicar conceitos das várias áreas do conhecimento para desenvolver o tema dentro dos limites estruturais do texto dissertativo-argumentativo. 200 pontos. O que é avaliado: entender o tema exatamente como proposto, usar o tipo textual correto (dissertativo-argumentativo), demonstrar repertório cultural variado. Fuga ao tema: nota 0. Tangenciamento: pontuação reduzida. Como garantir que não fugir ao tema. Análise de redações com tangenciamento.', ['Analise estas 3 redações: alguma foge ao tema? Alguma tangencia? Justifique.', 'Escreva apenas a introdução garantindo que ela mostra perfeito entendimento do tema proposto.']),
  createLesson('g3-por-b1-l7', 'L7: Redação ENEM — Competência 3 (Argumentação)', 'portugues', 'Competência 3: selecionar, relacionar, organizar e interpretar informações, fatos, opiniões e argumentos em defesa de um ponto de vista. 200 pontos. Estrutura argumentativa: tese → argumentos (com desenvolvimento) → contra-argumento opcional → conclusão. Argumentos eficazes: específicos, evidenciados, desenvolvidos. Repertório cultural: como citar de forma pertinente (não forçada). Progressão temática: cada parágrafo avança a discussão. Análise de redações nota 800 vs nota 200 na C3.', ['Reescreva este parágrafo de desenvolvimento fraco tornando-o forte na Competência 3.', 'Quais são os 3 argumentos mais sólidos para o tema proposto? Desenvolva o melhor deles.']),
  createLesson('g3-por-b1-l8', 'L8: Redação ENEM — Competência 4 (Coesão)', 'portugues', 'Competência 4: demonstrar conhecimento dos mecanismos linguísticos necessários para a construção da argumentação. 200 pontos. Coesão: uso de conectivos (operadores argumentativos), pronomes de referência, sinonímia, elipse. Conectivos mais importantes para a redação: adição, oposição/concessão, causa, consequência, conclusão, exemplificação, explicação. Erros de coesão: repetição excessiva, pronome sem antecedente claro, falta de conectivo. Exercícios específicos de coesão na redação.', ['Identifique todos os problemas de coesão nesta redação e corrija-os.', 'Reescreva este parágrafo usando pelo menos 4 mecanismos de coesão diferentes.']),
  createLesson('g3-por-b1-l9', 'L9: Redação ENEM — Competência 5 (Proposta de Intervenção)', 'portugues', 'Competência 5: elaborar proposta de intervenção para o problema abordado, respeitando os direitos humanos. 200 pontos. Os 5 elementos obrigatórios: agente (quem vai agir), ação (o que vai fazer), meio/modo (como vai fazer), finalidade (para quê), efeito/detalhamento (o que vai resultar). Cada elemento não mencionado reduz a nota. Direitos humanos: não pode propor violência, discriminação, ações inconstitucionais. Análise de propostas nota 200 e nota 40. Construção passo a passo.', ['Analise estas 3 propostas de intervenção: qual tem todos os 5 elementos? Qual está incompleta?', 'Escreva uma proposta de intervenção completa (com 5 elementos) para o tema: violência contra a mulher.']),
  createLesson('g3-por-b1-l10', 'L10: Gramática em Contexto — Concordância (ENEM)', 'portugues', 'Concordância verbal e nominal no ENEM: todas as questões são contextuais. Casos mais cobrados: sujeito composto posposto ao verbo, "um dos que" (plural), "mais de um" + singular ou plural, haver impessoal, pronomes indefinidos como sujeito, coletivo partitivo. Concordância nominal: adjetivo com múltiplos substantivos, "é proibido/é necessário", adjetivos compostos. Estratégia: identificar o sujeito real antes de concordar. Prática com 10 questões do ENEM.', ['Resolva estas 10 questões de concordância no contexto do ENEM.', 'Explique a concordância em cada uma destas frases complexas de textos reais.']),
  createLesson('g3-por-b1-l11', 'L11: Gramática em Contexto — Regência e Crase (ENEM)', 'portugues', 'Regência verbal e nominal + crase no ENEM. Verbos com regência que muda sentido: assistir (a = ver; sem preposição = ajudar), visar (a = objetivar; sem = mirar), implicar (a = acarretar; com = ser incompatível). Crase: obrigatória, facultativa e proibida — com foco nos casos que o ENEM usa. "Questão da crase antes de pronome demonstrativo aquela/aquele": crase ocorre. Palavras no singular vs. plural. Exercícios com questões reais.', ['Resolva estas 10 questões de regência e crase do ENEM.', 'Em quais casos de crase você ainda tem dúvida? Faça exercícios específicos.']),
  createLesson('g3-por-b1-l12', 'L12: Gramática em Contexto — Colocação e Pontuação (ENEM)', 'portugues', 'Colocação pronominal: o ENEM cobra em contexto literário e jornalístico. Próclise, ênclise, mesóclise — com foco em entender o efeito, não apenas a regra. Pontuação: a vírgula que muda o sentido (restritiva vs. explicativa). Dois-pontos e ponto-e-vírgula em textos formais. O ENEM raramente pede "classifique a vírgula" — pede "o que muda de sentido com ou sem vírgula". Prática com questões que exploram pontuação e colocação como mudança de sentido.', ['Resolva estas 8 questões do ENEM sobre colocação pronominal e pontuação.', 'Como a vírgula muda o sentido nestas frases? Explique.']),
  createLesson('g3-por-b1-l13', 'L13: Produção de Redação — Simulado 1', 'portugues', 'Primeiro simulado de redação do ano: condições reais do ENEM. Tema com 4-5 textos motivadores. 60 minutos. Avaliação completa: C1+C2+C3+C4+C5. Devolutiva individual e detalhada. Análise coletiva: erros mais comuns da turma. Estratégia de melhoria: cada aluno identifica sua competência mais fraca e traça plano específico. Este simulado é o ponto de partida — não o destino. A nota vai crescer.', ['Escreva a Redação Simulada 1 em 60 minutos.', 'Com base na devolutiva, qual competência você vai focar no próximo bimestre?']),
  createLesson('g3-por-b1-l14', 'L14: Textos Literários no ENEM — Modernismo', 'portugues', 'Modernismo é a escola mais cobrada no ENEM. Revisão focada: 1ª fase (ruptura, humor, experimentação — Oswald, Mário, Manuel Bandeira), 2ª fase prosa (engajamento social, regionalismo — Graciliano, Guimarães Rosa, Clarice Lispector), 2ª fase poesia (Drummond, Cecília Meireles), 3ª fase (concretismo, João Cabral). O ENEM usa fragmentos modernistas frequentemente. Prática: identificar a fase modernista e interpretar o fragmento. 10 questões reais.', ['Resolva estas 10 questões de Modernismo do ENEM.', 'Para cada fragmento modernista, identifique a fase e justifique com características textuais.']),
  createLesson('g3-por-b1-l15', 'L15: Textos Literários no ENEM — Outros Períodos', 'portugues', 'Revisão dos outros períodos literários mais cobrados no ENEM. Romantismo: indianismo, ultra-romantismo, condoreirismo. Realismo/Naturalismo: Machado de Assis (ironia, narrador não confiável), Aluísio Azevedo. Barroco: Gregório de Matos, Padre Vieira. Classicismo: Camões (quando aparece no ENEM). Pré-Modernismo: Euclides da Cunha, Lima Barreto. Literatura portuguesa: Fernando Pessoa. Literatura africana: Mia Couto. Prática com questões reais de cada período.', ['Resolva estas 10 questões de períodos literários variados do ENEM.', 'Monte uma tabela comparativa: escola, contexto, características, autores-chave, ENEM cobrado assim...']),
  createLesson('g3-por-b1-l16', 'L16: Figuras de Linguagem e Efeito de Sentido no ENEM', 'portugues', 'Figuras de linguagem no ENEM: foco total no efeito de sentido, não na nomenclatura. Questão típica: "O uso de [figura] neste trecho cria o efeito de..." Figuras mais cobradas: metáfora (transferência de sentido), metonímia (substituição por relação), hipérbole (exagero para efeito), ironia (dizer o contrário), antítese (oposição que revela contradição), eufemismo (suavização), personificação (humanizar o inanimado). Análise em contexto literário e publicitário.', ['Resolva estas 12 questões do ENEM sobre figuras de linguagem em contexto.', 'Para cada figura, escreva uma frase que mostre o efeito que ela cria — não apenas o que ela é.']),
  createLesson('g3-por-b1-l17', 'L17: Gêneros Textuais e Variação no ENEM', 'portugues', 'Gêneros textuais no ENEM: identificar o gênero e seu propósito. Questões típicas: "Este texto pertence ao gênero X porque...", "A linguagem deste texto é adequada porque...". Variação linguística: identificar registro (formal/informal/técnico), variação social ou regional, e seus efeitos. O ENEM valoriza o reconhecimento do preconceito linguístico: uma questão nunca vai dizer que uma variante é "errada". Prática com questões reais.', ['Resolva estas 10 questões do ENEM sobre gêneros textuais e variação linguística.', 'Analise: como o gênero e o registro estão relacionados neste texto?']),
  createLesson('g3-por-b1-l18', 'L18: Revisão do Bimestre 1 e Simulado Geral', 'portugues', 'Revisão do 1º Bimestre: planejamento estratégico, diagnóstico, masterclass de interpretação, literatura no ENEM, todas as 5 competências da redação, gramática em contexto (concordância, regência, crase, colocação, pontuação), figuras de linguagem, gêneros e variação. Simulado geral: 15 questões de LP estilo ENEM. Balanço: em que você melhorou? O que ainda falta? Ajuste do plano de estudos para o 2º Bimestre.', ['Resolva o simulado geral do 1º Bimestre (15 questões LP + planejamento de redação).', 'Atualize seu plano de estudos com base nos resultados do simulado.']),
];

export const porLessonsB2: Lesson[] = [
  createLesson('g3-por-b2-l1', 'L1: Redação — Simulado 2 e Devolutiva', 'portugues', 'Segundo simulado de redação: aplicando o feedback do primeiro. Novo tema, novas estratégias. Foco especial na competência mais fraca identificada no simulado 1. Avaliação e devolução com análise comparativa: houve melhora em relação ao simulado 1? Quais competências cresceram? Quais ainda precisam de trabalho? Ajuste do plano de treinamento de redação para o restante do ano. Mantra: cada redação escrita é prática real — não existe "praticar na cabeça".', ['Escreva a Redação Simulada 2 (60 minutos).', 'Compare sua nota C1-C5 no simulado 2 com o simulado 1: houve crescimento? Em quê?']),
  createLesson('g3-por-b2-l2', 'L2: Repertório Cultural para Redação', 'portugues', 'Construindo o "banco de repertório" para a redação. Categorias: filósofos e pensadores (Aristóteles, Kant, Marx, Simone de Beauvoir, Paulo Freire), dados e relatórios (IBGE, OMS, ONU, Fórum Econômico Mundial), autores literários (Machado, Drummond, Clarice), eventos históricos (Abolição, Ditadura, Declaração Universal dos DH), leis e documentos (Constituição Federal 1988, ECA, Lei Maria da Penha). Como usar repertório pertinente (não forçado). Cada tema tem um repertório natural.', ['Construa seu banco de repertório: 5 citações, 5 dados, 5 eventos históricos, 5 leis relevantes para redações.', 'Para este tema proposto, qual repertório você usaria? Seja específico.']),
  createLesson('g3-por-b2-l3', 'L3: Temas Recorrentes no ENEM — Análise e Preparação', 'portugues', 'Temas que mais aparecem no ENEM (análise 2009-2024). Educação (2 vezes), violência contra a mulher (2019), saúde mental (2022), comunidades quilombolas (2016), democratização da internet (2012), lixo e consumo (2010). Padrões: sempre temas sociais, ligados aos direitos humanos, com aspectos contraditórios na sociedade brasileira. Como identificar o verdadeiro "problema social" em um tema. Preparação temática: ter argumentos prontos para 10 temas prováveis.', ['Para 5 temas prováveis do ENEM, escreva: 1 tese + 2 argumentos + 1 proposta de intervenção.', 'Analise o tema do ENEM de 2023 e 2022: como você abordaria cada um?']),
  createLesson('g3-por-b2-l4', 'L4: Linguagem e Gênero — Análise Crítica', 'portugues', 'A língua e as relações de gênero. Generificação da linguagem: palavras com carga de gênero (médica vs. médico, a mulher que "se cuida"). Linguagem machista: expressões que naturalizam a subordinação feminina. Linguagem inclusiva: neutro de gênero (burocracia, -e), debate atual. Representação feminina na literatura: de objeto a sujeito. Escritoras na literatura brasileira: Clarice Lispector, Conceição Evaristo, Carolina Maria de Jesus ("Quarto de Despejo"), Rachel de Queiroz.', ['Analise a representação feminina neste texto literário: ela é objeto ou sujeito?', 'Que estratégias linguísticas este texto usa que podem ser consideradas machistas?']),
  createLesson('g3-por-b2-l5', 'L5: Literatura e Questão Racial', 'portugues', 'Literatura e raça no Brasil. Cruz e Sousa: simbolismo e negritude. Lima Barreto: preconceito racial no Brasil da Belle Époque. Carolina Maria de Jesus: "Quarto de Despejo" — a favela por dentro. Conceição Evaristo: "Escrevivência" — a escrita como resistência das mulheres negras. Literatura afro-brasileira: Cuti, Miriam Alves, Lino Guedes. O ENEM e a diversidade: questões sobre representatividade na literatura. A ausência como dado: quem não está representado?', ['Analise "Quarto de Despejo": como Carolina Maria de Jesus narra a vida na favela?', 'O que o conceito de "Escrevivência" de Conceição Evaristo representa para a literatura brasileira?']),
  createLesson('g3-por-b2-l6', 'L6: Análise de Textos do ENEM — Metodologia', 'portugues', 'Metodologia de análise de textos no ENEM. Passo 1: leia a questão antes do texto. Passo 2: leia o texto ativamente (marque palavras-chave). Passo 3: identifique tipo e gênero do texto. Passo 4: localize a informação pedida. Passo 5: avalie cada alternativa contra o texto. Armadilhas: alternativas "verdadeiras mas não baseadas no texto", alternativas que exageram ou minimizam o texto, alternativas com palavras absolutas (sempre, nunca, todos). Prática com questões difíceis (nível 3-4 do ENEM).', ['Resolva estas 8 questões difíceis do ENEM usando a metodologia passo a passo.', 'Para cada questão errada: identifique a armadilha que te pegou.']),
  createLesson('g3-por-b2-l7', 'L7: Questões de Interpretação — Inferência e Implicação', 'portugues', 'Inferência: o que o texto diz sem dizer. Tipos de inferência no ENEM: lógica (necessariamente verdadeiro), pragmática (provável no contexto), cultural (requer conhecimento de mundo). Implicatura: o que se comunica além do literal (Grice). Pressuposição vs. asserção. Questões típicas: "O que se pode concluir...", "O texto sugere que...", "O autor implica que...". Estratégia: a inferência deve ser 100% sustentada pelo texto — nunca "acho que" ou "faz sentido". Prática com 15 questões de inferência do ENEM.', ['Resolva estas 15 questões de inferência do ENEM.', 'Para cada inferência: indique exatamente que parte do texto a sustenta.']),
  createLesson('g3-por-b2-l8', 'L8: Redação — Treinamento por Competência I', 'portugues', 'Treinamento específico por competência. Hoje: C1 e C2. C1: exercícios de norma culta em texto completo — escrever sem erros. C2: exercícios de aderência ao tema — escrever introduções que mostram perfeito entendimento do tema. Comparação: introduções que tangenciam vs. introduções que aderem perfeitamente. O que é "fuga ao tema" vs. "abordagem criativa" (legítima). Desenvolvendo a consciência linguística: reler e perceber os próprios erros.', ['Escreva 3 introduções diferentes para o mesmo tema, focando em perfeita aderência (C2).', 'Corrija todos os erros de norma culta (C1) desta redação de aluno.']),
  createLesson('g3-por-b2-l9', 'L9: Redação — Treinamento por Competência II', 'portugues', 'Treinamento específico: C3 e C4. C3: construindo parágrafos de desenvolvimento sólidos — tópico frasal, argumento desenvolvido, evidência, conexão com a tese. Progressão temática: cada parágrafo avança. C4: usando conectivos corretamente — lista de conectivos por categoria com exemplos em redações reais. Substituindo repetição por sinonímia e referência. Treino: escrever apenas os parágrafos de desenvolvimento de uma redação, focando C3 e C4.', ['Escreva 2 parágrafos de desenvolvimento sólidos para o tema proposto (foco C3+C4).', 'Reescreva estes parágrafos melhorando a coesão (C4) sem mudar o conteúdo.']),
  createLesson('g3-por-b2-l10', 'L10: Redação — Treinamento por Competência III', 'portugues', 'Treinamento específico: C5 (proposta de intervenção). A proposta mais completa possível. Agente: específico (não "o governo" genérico — "o Ministério da Educação" / "as escolas públicas"). Ação: verbo de intervenção claro. Meio: como especificamente. Finalidade: para que resultado. Efeito/detalhamento: o que se espera que mude. Mínimo de 3 dos 5 elementos para nota acima de 80 em C5. Treino: produzir propostas cada vez mais completas e específicas para diferentes temas.', ['Escreva 3 propostas de intervenção completas (com todos os 5 elementos) para 3 temas diferentes.', 'Avalie estas propostas: quais elementos estão ausentes? Reescreva-as completando.']),
  createLesson('g3-por-b2-l11', 'L11: Intertextualidade e Parádia no ENEM', 'portugues', 'Intertextualidade: relação entre textos. Citação, alusão, referência, paródia, pastiche, releitura. O ENEM usa muito a intertextualidade: textos que dialogam com outros, anúncios que parodiam poemas, músicas que referenciam obras literárias. Questões típicas: "Este texto dialoga com X porque...", "A paródia presente no texto...", "O intertexto estabelecido cria o efeito de...". Reconhecer intertextualidade exige repertório cultural. Prática com questões reais.', ['Identifique o intertexto neste anúncio publicitário: a que texto ele alude?', 'Resolva estas 8 questões de intertextualidade do ENEM.']),
  createLesson('g3-por-b2-l12', 'L12: Simulado Integrado — ENEM (Meio de Ano)', 'portugues', 'Simulado de meio de ano: 15 questões de LP estilo ENEM + redação completa. Cobrindo todos os conteúdos até aqui: interpretação, literatura, gramática, figuras, gêneros, variação, intertextualidade. Redação: 60 minutos, tema social, avaliação pelas 5 competências. Análise de desempenho: comparação com os simulados anteriores. Projeção de nota: em que patamar você está? O que precisa para chegar onde quer?', ['Complete o simulado de meio de ano (questões + redação).', 'Calcule sua nota projetada de LP: 15 questões × 5 pontos + redação. Onde você precisa chegar?']),
  createLesson('g3-por-b2-l13', 'L13: Texto Publicitário e Crítica do Consumo', 'portugues', 'Publicidade e consumo: análise crítica. Estratégias persuasivas: ethos (credibilidade), pathos (emoção), logos (razão). Técnicas específicas: urgência (compre agora!), escassez (últimas unidades), prova social (todos estão comprando), autoridade (recomendado por especialistas), personalização. Publicidade e estereótipos de gênero, raça, classe. Contrapublicidade (subvertive ads): usar a linguagem da publicidade para criticá-la. O ENEM usa anúncios e analisa seus efeitos.', ['Analise este anúncio: que estratégias usa? A quem se dirige? Que estereótipos reforça?', 'Crie uma contrapublicidade subvertendo um anúncio real (visual + texto).']),
  createLesson('g3-por-b2-l14', 'L14: Literatura Contemporânea e Periférica', 'portugues', 'Literatura brasileira do séc. XXI: diversidade de vozes antes silenciadas. Literatura periférica: narrativas da favela, da periferia urbana — Ferréz ("Capão Pecado"), Marcelino Freire. Slam poetry: competições de poesia falada — palco para vozes marginalizadas. Literatura indígena: Daniel Munduruku, Ailton Krenak ("Ideias para Adiar o Fim do Mundo"). Literatura LGBTQIA+. Mulheres escritoras: Djamila Ribeiro, Chimamanda Adichie (em tradução). O ENEM e a diversidade literária crescente.', ['Leia um texto de Conceição Evaristo ou Ailton Krenak e analise: que visão de mundo ele apresenta?', 'Por que a inclusão de literaturas periféricas e indígenas no currículo é importante?']),
  createLesson('g3-por-b2-l15', 'L15: Síntese e Paráfrase — Habilidades Essenciais', 'portugues', 'Síntese: condensar um texto sem perder as ideias centrais. Paráfrase: reescrever com outras palavras mantendo o sentido. Estas habilidades são essenciais na redação (para usar textos motivadores sem copiar), no estudo (para fixar conteúdo), e no ENEM (para reformular textos nas questões de gramática). Diferença: síntese reduz; paráfrase mantém o tamanho mas muda as palavras. Prática progressiva de síntese (1/2, 1/3, 1/4 do texto original).', ['Sintetize este editorial em 50 palavras (original tem 250 palavras).', 'Parafraseie estes 3 parágrafos de textos motivadores para usar em uma redação.']),
  createLesson('g3-por-b2-l16', 'L16: Produção de Redação — Tema Educação', 'portugues', 'Prática de redação sobre educação (tema recorrente no ENEM). "Desafios para a inclusão digital na educação pública brasileira". Repertório específico: dados do IBGE sobre acesso à internet, Lei 9.394/96 (LDB), programa Internet para Todos, pesquisa TIC Educação (Cetic.br). Proposta de intervenção: Ministério da Educação + escolas + empresas de tecnologia. Foco: proposta específica, dados reais, argumentos desenvolvidos. Revisão e feedback.', ['Escreva a redação completa sobre o tema de educação (60 minutos).', 'Avalie especificamente a C5 (proposta de intervenção): está completa e específica?']),
  createLesson('g3-por-b2-l17', 'L17: Revisão de Gramática — Sintaxe no ENEM', 'portugues', 'Sintaxe no ENEM: não é análise gramatical direta, mas entender como a estrutura da frase cria sentido. Questões de sintaxe no ENEM: "O período X poderia ser reescrito como Y sem alteração de sentido?", "A supressão da vírgula altera o sentido porque...", "O pronome X retoma o termo Y...". Orações subordinadas: reconhecer o tipo e o sentido que expressam (causal, concessiva, condicional, etc.). Prática com questões de nível difícil.', ['Resolva estas 8 questões de sintaxe em contexto do ENEM.', 'Como a ordem dos termos muda o foco/ênfase neste texto? Analise.']),
  createLesson('g3-por-b2-l18', 'L18: Revisão do Bimestre 2', 'portugues', 'Revisão do 2º Bimestre: simulados de redação (1 e 2), repertório cultural, temas recorrentes do ENEM, linguagem e gênero/raça, metodologia de análise, inferência e implicação, treinamento por competência (C1-C5), intertextualidade, simulado integrado, publicidade crítica, literatura contemporânea, síntese e paráfrase, gramática/sintaxe no ENEM. Balanço do primeiro semestre completo. Você está na metade do caminho rumo ao ENEM.', ['Resolva o simulado de revisão do 2º Bimestre.', 'Onde você estava no início do ano e onde está agora em LP? Avalie honestamente.']),
];

export const porLessonsB3: Lesson[] = [
  createLesson('g3-por-b3-l1', 'L1: Sprint ENEM — Língua Portuguesa', 'portugues', 'Com o ENEM se aproximando, o ritmo intensifica. Revisão dos erros mais comuns dos estudantes brasileiros no ENEM de LP: interpretar a partir do senso comum (não do texto), confundir o tema com o assunto superficial, usar repertório de forma mecânica na redação, fugir ao tema por excesso de criatividade, ignorar a proposta de intervenção. Foco: consolidar pontos fortes e eliminar erros sistemáticos. Estratégia de estudo das últimas semanas antes do ENEM.', ['Faça um inventário dos seus principais erros em LP no ENEM. Como você vai corrigi-los?', 'Qual é o seu plano de estudo de LP para as últimas semanas antes do ENEM?']),
  createLesson('g3-por-b3-l2', 'L2: Simulado ENEM Real — Linguagens 2022', 'portugues', 'Simulado completo com o caderno de Linguagens do ENEM 2022 (apenas as questões de LP e Literatura). 15 questões selecionadas das mais relevantes. Condições de prova: tempo marcado, sem consulta. Análise completa: questão por questão, explicando por que a correta é correta e por que as erradas são erradas. Identificação de padrões do ENEM 2022: que habilidades foram mais cobradas? Comparação com anos anteriores.', ['Resolva o simulado do ENEM 2022 (questões de LP e Literatura) sob condições reais.', 'Analise: que tipos de questão aparecem mais? Em quais você acertou/errou mais?']),
  createLesson('g3-por-b3-l3', 'L3: Simulado ENEM Real — Linguagens 2023', 'portugues', 'Simulado completo com o caderno de Linguagens do ENEM 2023. Mesmo formato do dia anterior: 15 questões selecionadas, condições de prova, análise detalhada. Comparação com o simulado de 2022: houve diferença no nível? Nos temas? Nos tipos de texto? Nas habilidades cobradas? Construindo uma compreensão holística do que é o ENEM de LP. Calculando: se fosse o ENEM real, qual seria sua nota?', ['Resolva o simulado do ENEM 2023 sob condições reais.', 'Compare seu desempenho nos simulados 2022 e 2023: houve diferença? Por quê?']),
  createLesson('g3-por-b3-l4', 'L4: Redação — Simulado 3', 'portugues', 'Terceiro simulado de redação: mais próximo do ENEM. Tema proposto com textos motivadores complexos. 60 minutos. Avaliação rigorosa — mesmos critérios da banca do ENEM. Atenção especial: a proposta de intervenção é o item mais fácil de aprimorar rapidamente (sempre inclua os 5 elementos). Devolutiva: notas por competência + comentários qualitativos. Comparação com simulados 1 e 2: trajetória de crescimento. Nota final projetada.', ['Escreva a Redação Simulada 3 (60 minutos).', 'Compare as notas dos 3 simulados: qual foi a maior evolução? O que ainda falta?']),
  createLesson('g3-por-b3-l5', 'L5: Questões Difíceis — Resolução Comentada', 'portugues', 'Aula focada nas questões mais difíceis do ENEM de LP (nível 4-5 de dificuldade). Questões que exigem: inferência profunda, análise estilística sofisticada, reconhecimento de intertextualidade complexa, análise de discurso, compreensão de ironia ou humor. Resolução passo a passo: como um especialista abordaria cada questão. Processo de eliminação: por que cada alternativa errada está errada. A dificuldade tem lógica — aprender essa lógica é treináve.', ['Tente resolver estas 10 questões difíceis antes de ver a resolução comentada.', 'Para as que você errou: qual foi o raciocínio correto que você não seguiu?']),
  createLesson('g3-por-b3-l6', 'L6: Discurso, Ideologia e Análise Crítica', 'portugues', 'Análise crítica do discurso no ENEM. Todo texto é produzido em um contexto histórico e social — nenhum texto é neutro. Análise de textos políticos, midiáticos, publicitários: quem fala? Para quem? Com que propósito? Que visão de mundo está sendo construída? Questões do ENEM que pedem: "O texto revela que o autor...", "A perspectiva adotada no texto é...". Desenvolvendo a leitura crítica — não paranoia, mas consciência. Prática com textos políticos reais.', ['Analise este discurso político: que imagem de Brasil ele constrói? Quem inclui e quem exclui?', 'Resolva estas 5 questões do ENEM que exigem análise crítica do discurso.']),
  createLesson('g3-por-b3-l7', 'L7: A Redação Nota 1000 — Análise Detalhada', 'portugues', 'Análise detalhada de redações nota 1000 do ENEM (temas variados). O que as une: perfeita aderência ao tema, argumento sólido e progressivo, coesão refinada, proposta criativa e detalhada, zero erros graves de norma. O que as distingue das redações nota 800: a profundidade do argumento, a especificidade da proposta, a elegância da coesão. Você não precisa de uma nota 1000 — mas entender o que é excelente melhora qualquer nota. Critérios internalizados.', ['Analise esta redação nota 1000 competência por competência: o que ela faz muito bem?', 'Compare esta redação nota 1000 com uma nota 600 no mesmo tema: o que é diferente?']),
  createLesson('g3-por-b3-l8', 'L8: Dicas de Dia de Prova — ENEM LP e Redação', 'portugues', 'Estratégias para o dia do ENEM. Caderno de Linguagens e Redação: sempre o SEGUNDO dia (domingo). Tempo: 5h30 para 45 questões + redação. Gerência de tempo: 3h para as questões (4 minutos/questão) + 1h20 para a redação + 10 min de revisão. Questões de LP: fazer primeiro (confiança), ou depois da redação? Estratégia pessoal. A redação: nunca deixe em branco (nota mínima > nota 0). Revisão: ler toda a redação antes de entregar. Comer, dormir, chegar cedo.', ['Qual é sua estratégia pessoal de tempo para o ENEM de Linguagens e Redação?', 'O que você vai fazer na noite anterior ao ENEM? Monte um roteiro de preparação.']),
  createLesson('g3-por-b3-l9', 'L9: Pós-ENEM — Vestibulares Específicos', 'portugues', 'Alguns alunos farão vestibulares além do ENEM. FUVEST (USP): LP com gramática mais explícita, redação dissertativa. UNICAMP: redação múltipla (carta, editorial, etc.). UFT: vestibular próprio com conteúdo do Tocantins. Outros: UFMG, PUC. Português para vestibulares específicos: o que é diferente do ENEM. Preparação específica para quem fará mais de um exame. Gestão de tempo e energia: não se esgotar tentando fazer tudo.', ['Pesquise: o vestibular da universidade que você quer como funciona em LP? O que é diferente do ENEM?', 'Se você vai fazer vestibular além do ENEM, como vai organizar sua preparação?']),
  createLesson('g3-por-b3-l10', 'L10: Leitura Literária Final — Obras para Vida', 'portugues', 'Obras literárias que todo estudante deveria conhecer antes de sair do Ensino Médio. Lista essencial: Machado de Assis ("Dom Casmurro" ou "Memórias Póstumas"), Graciliano Ramos ("Vidas Secas"), Carlos Drummond de Andrade (poemas selecionados), Clarice Lispector ("A Hora da Estrela" ou contos), Guimarães Rosa (contos), Carolina Maria de Jesus ("Quarto de Despejo"), Conceição Evaristo (contos). Por que estas obras? Como elas formam o cidadão? Leitura de trechos e discussão.', ['Qual destas obras você já leu? Qual vai ler? Faça um plano de leitura.', 'Leia este trecho de uma dessas obras e descreva em 5 frases o que ele diz sobre o Brasil.']),
  createLesson('g3-por-b3-l11', 'L11: Simulado Final Completo — LP', 'portugues', 'Simulado final completo de LP: 15 questões no nível exato do ENEM. Cobertura total: interpretação (todos os tipos de texto), literatura (todas as escolas), gramática em contexto, figuras de linguagem, variação, gêneros, intertextualidade. Condições: tempo marcado (40 minutos), sem consulta. Análise: nota bruta + identificação de padrão de erros. Este é o diagnóstico final — o que seu ENEM real pode ser, a princípio.', ['Resolva o Simulado Final de LP (15 questões em 40 minutos).', 'Com base neste resultado, você está preparado para o ENEM de LP? O que ainda falta?']),
  createLesson('g3-por-b3-l12', 'L12: Redação — Simulado Final', 'portugues', 'Simulado final de redação: as condições mais próximas do ENEM possível. Tema proposto com 4 textos motivadores. 60 minutos sem interrupção. Avaliação com máxima rigorosidade. Devolutiva: nota final por competência e holística estimada. Este simulado não é para mudar estratégia — é para confirmar que você está pronto. Mensagem: você praticou, você cresceu, você está mais preparado do que estava. Confie no trabalho feito.', ['Escreva o Simulado Final de Redação (60 minutos).', 'Esta é sua melhor redação até agora? Se não, o que faltou? Se sim, você está pronto!']),
  createLesson('g3-por-b3-l13', 'L13: Preparação Emocional para o ENEM', 'portugues', 'O ENEM não é só prova de conhecimento — é prova de preparo emocional. Ansiedade de prova: normal até certo ponto, paralisante se excessiva. Técnicas: respiração, visualização positiva, preparação física (sono, alimentação), chegar cedo, confiar na preparação. "Não sei essa" → "já vi coisa assim, vou aplicar o que sei." Autoeficácia: a crença na própria capacidade aumenta o desempenho. Você trabalhou — agora é hora de mostrar. A língua portuguesa é sua. Use-a.', ['O que você faz quando trava em uma questão? Qual é sua estratégia de desempato?', 'Escreva uma carta para si mesmo para abrir no dia do ENEM: o que você quer se lembrar?']),
  createLesson('g3-por-b3-l14', 'L14: Português para a Vida Pós-ENEM', 'portugues', 'A língua portuguesa além do ENEM. Na universidade: leitura acadêmica, produção de TCC, artigos, apresentações. No trabalho: e-mails profissionais, relatórios, comunicação assertiva. Na vida cidadã: ler contratos, entender notícias, participar de debates. Na vida pessoal: se expressar, se defender, criar. O domínio da língua como liberdade: quem escreve bem tem mais poder. Mantendo a prática após o ENEM: ler regularmente, escrever, ouvir debates.', ['Que competências de LP vão ser mais importantes para sua vida após o Ensino Médio?', 'Como você vai manter e desenvolver suas habilidades em língua portuguesa após o ENEM?']),
  createLesson('g3-por-b3-l15', 'L15: Projeto — Jornal/Blog Literário da Turma', 'portugues', 'Projeto final de Língua Portuguesa: produzir um jornal ou blog literário colaborativo da turma. Cada aluno contribui com: uma produção criativa (conto, poema, crônica), uma crítica literária (de um livro que leu), uma coluna de opinião (sobre tema atual). Editoração coletiva: selecionar, editar, publicar. O produto final circula na escola e/ou online. Demonstrando: a língua como prática viva, coletiva, significativa. A turma como comunidade de escritores e leitores.', ['Contribua com sua parte para o jornal/blog literário: crie ou revise seu texto.', 'Escreva uma breve nota editorial coletiva (por que este jornal existe? O que queremos dizer?).']),
  createLesson('g3-por-b3-l16', 'L16: Celebração da Leitura e da Escrita', 'portugues', 'Celebração: leitura dos melhores textos produzidos no ano. Sarau literário: poemas, crônicas, contos, artigos. Cada aluno compartilha o texto de que mais se orgulha. Reflexão coletiva: o que a língua portuguesa nos deu este ano? Como crescemos como leitores? Como escritores? Como cidadãos? O percurso de 3 anos de LP no Ensino Médio: onde começamos, onde chegamos. A língua como nossa maior riqueza coletiva.', ['Leia seu texto favorito do ano em voz alta para a turma.', 'Escreva um parágrafo sobre o que a língua portuguesa significa para você.']),
  createLesson('g3-por-b3-l17', 'L17: Revisão de Urgência — Últimos Pontos', 'portugues', 'Revisão ultra-focada nos pontos que mais caem e que você ainda tem dúvida. Cada aluno traz sua lista dos 5 pontos mais difíceis. Resolução em equipe: quem sabe, ensina. Questões rápidas de múltipla escolha sobre os pontos críticos. Última rodada de gramática: os 10 casos que sempre aparecem. Última rodada de literatura: as 5 obras mais cobradas. Última revisão da estrutura da redação. Você está mais pronto do que pensa.', ['Liste os 5 pontos de LP que ainda geram dúvida. Vamos resolver juntos.', 'Resolva este quiz rápido dos 15 conteúdos mais cobrados: está preparado?']),
  createLesson('g3-por-b3-l18', 'L18: Véspera do ENEM — Última Aula de LP', 'portugues', 'A última aula de Língua Portuguesa antes do ENEM. O que fazer e o que não fazer. Não: estudar pesado na véspera, fazer simulado, reler tudo. Sim: revisar levemente, preparar o material (documento, caneta), dormir bem, planejar a logística. Mensagem final: você passou 12 anos aprendendo a ler, escrever, interpretar e argumentar. O ENEM testa o que você sabe — e você sabe muito. Vá com confiança. A língua portuguesa é sua. Use-a bem.', ['Qual é o seu plano para a véspera do ENEM? Escreva-o.', 'Escreva sua última mensagem para seus colegas antes do ENEM.']),
];

export const porLessonsB4: Lesson[] = [
  createLesson('g3-por-b4-l1', 'L1: Pós-ENEM — Reflexão e Resultados', 'portugues', 'O ENEM passou. Qualquer que seja o resultado, você deu um passo importante. Reflexão sobre a experiência: como foi a prova de LP? As questões foram como esperado? A redação correu bem? O que você faria diferente? Para quem vai aguardar o resultado: mantendo a calma e a esperança. Para quem vai refazer o ENEM: o que mudar na preparação. Para todos: a jornada de aprendizado não termina com o ENEM.', ['Escreva uma reflexão honesta sobre como foi o ENEM para você.', 'O que você aprendeu sobre si mesmo como estudante durante esta preparação?']),
  createLesson('g3-por-b4-l2', 'L2: Língua Portuguesa na Universidade', 'portugues', 'Português acadêmico: como a língua é usada na universidade. Gêneros acadêmicos: resumo, resenha, fichamento, artigo científico, ensaio acadêmico, monografia/TCC, relatório. Citação e referências (ABNT). Plágio: o que é, por que é grave, como evitar. Leitura acadêmica: como ler textos acadêmicos com eficiência. Vocabulário acadêmico: termos comuns em diferentes cursos. Preparação para qualquer curso superior: a LP acadêmica é transversal.', ['Escreva um resumo acadêmico de um texto indicado usando a estrutura correta.', 'O que é plágio? Reescreva esta passagem parafraseando corretamente (sem plagiar).']),
  createLesson('g3-por-b4-l3', 'L3: Literatura Brasileira — Grandes Sínteses', 'portugues', 'Síntese de toda a literatura brasileira estudada no Ensino Médio. Periodização literária: tendências e contextos históricos que criam cada escola. A narrativa da literatura brasileira: de colônia a nação, de imitação a originalidade, de minoria a diversidade. Grandes temas da literatura brasileira: identidade nacional, raça, sertão, cidade, mulher, exílio, morte, amor. Grandes autores em perspectiva: por que Machado, Drummond, Clarice ainda importam hoje. A literatura como memória coletiva do Brasil.', ['Conte a história da literatura brasileira em 400 palavras: sem nomes próprios, usando apenas temas e transformações.', 'Por que ainda ler Machado de Assis no século XXI? Construa um argumento.']),
  createLesson('g3-por-b4-l4', 'L4: Produção Textual Avançada — Ensaio', 'portugues', 'Ensaio acadêmico: reflexão aprofundada sobre um tema, combinando rigor intelectual e expressão pessoal. Diferente da dissertação do ENEM: menos prescritivo, mais reflexivo, mais longo. Estrutura: tese, desenvolvimento reflexivo (não apenas argumentativo), voz própria do ensaísta, síntese. Exemplos: Montaigne, Oswaldo de Andrade, Antonio Candido. Escrever um ensaio curto sobre um tema de escolha livre — exercitando a voz autoral.', ['Escreva um ensaio de 400 palavras sobre um tema que te apaixona em literatura ou língua.', 'Qual é a diferença entre o ensaio e a dissertação argumentativa? Exemplifique.']),
  createLesson('g3-por-b4-l5', 'L5: Língua, Identidade e Pertencimento', 'portugues', 'A língua como marcador de identidade e pertencimento. Como a língua que falamos define quem somos e onde pertencemos. Língua materna: o que perdemos quando perdemos a língua (povos indígenas, imigrantes). Bilinguismo e multilinguismo no Brasil: comunidades alemãs, italianas, japonesas, indígenas. Língua e classe social: diferentes registros como passaportes sociais. A língua como direito humano (UNESCO). Tocantins: línguas indígenas em risco — o que preservar significa.', ['Pesquise uma língua indígena do Tocantins em risco. O que a perda dessa língua representa?', 'Como sua língua (o Português tocantinense) te define? O que ela carrega de único?']),
  createLesson('g3-por-b4-l6', 'L6: Produção de Carta — Gêneros Epistolares', 'portugues', 'Gêneros epistolares: carta pessoal, carta formal, carta aberta, carta de leitor, carta-resposta. Estrutura da carta formal: local e data, destinatário, vocativo, corpo, despedida, assinatura. Carta aberta: de interesse público, publicada. Carta de leitor: resposta a texto publicado. Email como carta digital. Bilhetes e mensagens informais. A carta como gênero que revela o tempo histórico: cartas de escravizados, cartas da guerra, cartas de imigrantes. Escrever uma carta ao futuro.', ['Escreva uma carta formal ao reitor da universidade que você deseja ingressar.', 'Escreva uma carta pessoal a você mesmo para ser aberta em 10 anos.']),
  createLesson('g3-por-b4-l7', 'L7: Projeto Final — Memórias do Ensino Médio', 'portugues', 'Projeto final da 3ª série: produzir um texto memorialístico sobre a experiência do Ensino Médio. Gênero: memórias, crônica memorialística, ou ensaio autobiográfico. Conteúdo: momentos marcantes, aprendizados, amizades, desafios, transformações. Linguagem: primeira pessoa, subjetividade, seleção de memórias significativas. Reflexão: quem você era quando entrou no Ensino Médio? Quem você é agora? O que a escola (e a língua portuguesa) te deu? Publicação no jornal/blog da turma.', ['Escreva seu texto memorialístico do Ensino Médio (300-400 palavras).', 'Compartilhe com a turma: leia um trecho que considere especialmente significativo.']),
  createLesson('g3-por-b4-l8', 'L8: Discurso de Formatura — Gênero e Produção', 'portugues', 'O discurso de formatura como gênero: oratória, retórica, performance. Estrutura: exórdio (captação da atenção), narratio (narrativa da trajetória), argumentatio (reflexões e lições), peroratio (encerramento emocionante). Tom: solene mas autêntico, grato mas crítico, esperançoso mas realista. Clichês a evitar: "foi uma longa jornada", "os melhores anos da minha vida". Como escrever um discurso que ressoa. Apresentação oral: dicção, pausa, emoção, olhar. Escrever e apresentar um mini-discurso.', ['Escreva um mini-discurso de formatura (1 minuto, 150 palavras) autêntico e pessoal.', 'Apresente seu discurso para a turma: pratique a oralidade com emoção e clareza.']),
  createLesson('g3-por-b4-l9', 'L9: Língua Portuguesa e Cidadania', 'portugues', 'A língua como instrumento de cidadania. Ler e escrever como direitos humanos (Paulo Freire). O analfabetismo funcional no Brasil: 30% dos adultos não compreendem textos simples. O que isso significa para a democracia. Você, como letrado, tem responsabilidade: compartilhar informação, combater desinformação, ajudar quem não domina a leitura. Projetos de letramento comunitário. A LP que você aprendeu não é só sua — é de todos. Use-a para incluir, não para excluir.', ['O que você pode fazer com suas habilidades de LP para contribuir com sua comunidade?', 'Escreva um texto de opinião sobre o analfabetismo funcional no Brasil — use dados reais.']),
  createLesson('g3-por-b4-l10', 'L10: O Leitor que Você Se Tornou', 'portugues', 'Reflexão sobre a trajetória como leitor e escritor. Comparar: o texto que você escreveria no 1º ano do Ensino Médio vs. o que você escreve agora. Quais habilidades você desenvolveu? O que ainda está desenvolvendo? A leitura e a escrita como práticas que duram a vida inteira — não há ponto de chegada. Construindo a identidade de leitor: ter livros favoritos, gêneros preferidos, autores admirados. Quem é você como leitor?', ['Escreva sobre quem você era como leitor no início do Ensino Médio e quem você é agora.', 'Quais 3 obras você vai ler nos próximos 2 anos? Por que escolheu estas?']),
  createLesson('g3-por-b4-l11', 'L11: Avaliação Final e Portfólio', 'portugues', 'Avaliação final do percurso de 3 anos de Língua Portuguesa no Ensino Médio. Portfólio: coleção dos melhores textos das 3 séries. Autoavaliação: competências desenvolvidas, desafios superados, crescimento documentado. Avaliação do professor: feedback final sobre o desenvolvimento de cada aluno. A nota como representação parcial do aprendizado — o mais importante é o que fica depois que a nota passa.', ['Monte seu portfólio final: selecione o melhor texto de cada ano do Ensino Médio.', 'Escreva uma autoavaliação do seu percurso completo de LP no Ensino Médio.']),
  createLesson('g3-por-b4-l12', 'L12: Sarau Literário Final — Celebração', 'portugues', 'Aula de celebração: sarau literário da turma formanda. Cada aluno apresenta: seu texto favorito (produzido no Ensino Médio), uma leitura de um poema ou trecho literário que ama, uma palavra que leva do Ensino Médio. A turma como comunidade de leitores e escritores que se encontraram. O que a língua portuguesa nos deu: voz, pensamento, conexão, beleza. "A palavra é o mais poderoso instrumento que existe." Use-a bem.', ['Prepare sua apresentação para o sarau: texto + leitura + palavra.', 'Escreva uma dedicatória para a antologia final da turma.']),
  createLesson('g3-por-b4-l13', 'L13: Literatura e o Futuro do Brasil', 'portugues', 'Que Brasil queremos? A literatura como visão de futuro. Textos utópicos e distópicos na literatura brasileira e mundial. O papel da literatura na construção do imaginário coletivo. Autores que imaginam o futuro: ficção científica brasileira (ficção de antecipação). Ailton Krenak ("Ideias para Adiar o Fim do Mundo"): outro modo de habitar o mundo. O que a leitura nos diz sobre o Brasil que queremos construir? Você, como cidadão letrado, é co-autor desse futuro.', ['Que futuro você deseja para o Brasil? Escreva um texto criativo (conto, crônica ou poema) sobre isso.', 'Que papel a língua portuguesa tem na construção do Brasil que você quer?']),
  createLesson('g3-por-b4-l14', 'L14: Mensagem Final — A Língua é Sua', 'portugues', 'Última aula de Língua Portuguesa do Ensino Médio. 12 anos de estudo da língua. Você chegou sabendo falar — e agora sabe argumentar, interpretar, criar, persuadir, analisar, questionar. A língua portuguesa é sua herança e sua ferramenta. Use-a para defender seus direitos. Para contar sua história. Para entender o mundo. Para transformá-lo. Parabéns pela conclusão do Ensino Médio. O futuro começa agora — e você tem palavras para construí-lo.', ['Escreva uma mensagem para a turma e para o professor sobre o que LP significou para você.', 'Qual é a primeira coisa que você vai fazer com suas habilidades de leitura e escrita após se formar?']),
  createLesson('g3-por-b4-l15', 'L15: Encerramento e Entrega de Portfólios', 'portugues', 'Cerimônia de encerramento do ano letivo de Língua Portuguesa. Entrega e exposição dos portfólios finais. Leitura dos melhores textos do ano pela turma. Reconhecimento: o texto que mais emocionou, o que mais provocou reflexão, o que mais fez rir. Foto coletiva com os portfólios. Mensagem do professor para a turma formanda. O Colégio Estadual Frederico Pedreira Neto se despede de vocês como escritores. Que a língua portuguesa seja sempre sua aliada.', ['Participe da cerimônia de encerramento compartilhando seu melhor texto.', 'Assine o portfólio de um colega com uma mensagem de encorajamento.']),
  createLesson('g3-por-b4-l16', 'L16: Redação para o Futuro — Últimos Treinos', 'portugues', 'Para quem ainda vai fazer vestibulares ou ENEM do ano seguinte: continuando o treino. Novos temas para treinar: mobilidade urbana, impacto da IA na sociedade, culturas indígenas brasileiras, saúde mental dos jovens. Cada tema: tese + 2 argumentos + proposta. Escrever uma dissertação completa por semana — mesmo nas férias. A redação é músculo: precisa de exercício constante. Dicas para manter o treino sem escola.', ['Escreva uma redação sobre um dos temas sugeridos como treino extra.', 'Monte um plano de treino de redação para as próximas 4 semanas pós-escola.']),
  createLesson('g3-por-b4-l17', 'L17: Projeto Interdisciplinar Final', 'portugues', 'Projeto interdisciplinar: LP + todas as disciplinas. Cada aluno produz um texto que integre conhecimentos de múltiplas áreas. Formato livre: artigo, reportagem, ensaio, conto de ficção científica. Tema: um problema real do Tocantins e soluções possíveis (usando conhecimento de biologia, química, história, geografia, filosofia, sociologia — em texto de LP). Demonstrando que a língua portuguesa é o veículo de todo o conhecimento. Apresentação e debate final.', ['Produza seu texto interdisciplinar sobre um problema real do Tocantins (mínimo 400 palavras).', 'Apresente seu texto e responda a 2 perguntas da turma sobre suas escolhas.']),
  createLesson('g3-por-b4-l18', 'L18: Formatura — A Última Aula', 'portugues', 'A última aula. Não de Língua Portuguesa — de Ensino Médio. Aqui, nesta sala, com estes colegas, este professor, estas palavras. O que você leva: não as regras de concordância (que podem ser consultadas), mas a capacidade de pensar, de se expressar, de questionar, de criar. "Uma língua é um dialeto que tem um exército e uma marinha" — Max Weinreich. O Português Brasileiro tem 215 milhões de falantes. E você é um deles. Com voz. Com história. Com futuro. Parabéns, formando/a.', ['Leia sua mensagem final para a turma em voz alta.', 'Escreva a primeira linha do texto que você vai produzir com tudo que aprendeu neste Ensino Médio.']),
];
